(function (window, undefined) {
	let loader;
	let elements = {};
	let apiKey = '';
	let errTimeout = null;
	let tokenTimeot = null;
	let modalTimeout = null;
	let textToImageSettings = {
		model: 'dall-e-2',
		n: 1,
		response_format: 'b64_json',
		size: '512x512',
		style: 'vivid',
		hd: false,
		maxTokens: 1000
	};
	const localStorageKey = 'AI_text_to_image_settings';
	const url = 'https://api.openai.com/v1/images/generations';
	window.Asc.plugin.init = function() {
		sendPluginMessage({type: 'onWindowReady'});
		addSlidersListeners();
		addTitlelisteners();
		initElements();
		createSelects();
		restoreSettings();

		elements.checkBoxQuality.onclick = function(e) {
			textToImageSettings.hd = e.target.checked;
		};

		elements.btnGenerate.onclick = function(e) {
			let prompt = elements.prompt.value.trim();
			if (prompt) {
				fetchData(getSettings(prompt));
			} else {
				elements.prompt.classList.add('error_border');
			}
		};

		elements.btnSettings.onclick = function() {
			elements.divParams.classList.toggle('hidden');
			elements.arrow.classList.toggle('arrow_down');
			elements.arrow.classList.toggle('arrow_up');
		};

		elements.prompt.oninput = function(event) {
			elements.prompt.classList.remove('error_border');
			if (tokenTimeot) {
				clearTimeout(tokenTimeot);
				tokenTimeot = null;
			}
			tokenTimeot = setTimeout(function() {
				let text = event.target.value.trim();
				let tokens = window.Asc.OpenAIEncode(text);
				elements.lbTokens.innerText = tokens.length;
				checkLen();
			}, 250);

		};

		elements.prompt.onkeydown = function(e) {
			if ( (e.ctrlKey || e.metaKey) && e.key === 'Enter') {
				submitHandler();
			}
		};

		elements.divTokens.onmouseenter = function() {
			elements.modal.classList.remove('hidden');
			if (modalTimeout) {
				clearTimeout(modalTimeout);
				modalTimeout = null;
			}
		};

		elements.divTokens.onmouseleave = function() {
			modalTimeout = setTimeout(function() {
				elements.modal.classList.add('hidden');
			},100)
		};

		elements.modal.onmouseenter = function() {
			if (modalTimeout) {
				clearTimeout(modalTimeout);
				modalTimeout = null;
			}
		};

		elements.modal.onmouseleave = function() {
			elements.modal.classList.add('hidden');
		};
	};

	function restoreSettings() {
		try {
			let value = localStorage.getItem(localStorageKey);
			if (value) {
				textToImageSettings = JSON.parse(value);
				changeParas(true);
			}
		} catch (error) {
			// we have some problem with saved message. we should remove it from localStorage
			localStorage.removeItem(localStorageKey);
		}
	};

	function initElements() {
		elements.btnGenerate     = document.getElementById('btn_generate');
		elements.prompt          = document.getElementById('textarea');
		elements.content         = document.getElementById('div_content');
		elements.modal           = document.getElementById('div_modal');
		elements.lbModalLen      = document.getElementById('lb_modal_length');
		elements.divTokens       = document.getElementById('div_tokens');
		elements.lbTokens        = document.getElementById('lb_tokens');
		elements.btnSettings     = document.getElementById('div_show_settings');
		elements.arrow           = document.getElementById('arrow');
		elements.divParams       = document.getElementById('div_parametrs');
		elements.selectModels    = document.getElementById('sel_models');
		elements.selectSize      = document.getElementById('sel_size');
		elements.selectResFormat = document.getElementById('sel_response_format');
		elements.selectStyle     = document.getElementById('sel_style');
		elements.inpCountSl      = document.getElementById('inp_count_sl');
		elements.lblCount        = document.getElementById('lb_count');
		elements.checkBoxQuality = document.getElementById('inp_quality');
		elements.mainError      = document.getElementById('div_err');
		elements.mainErrorLb    = document.getElementById('lb_err');
	};

	function addSlidersListeners() {
		const rangeInputs = document.querySelectorAll('input[type="range"]');

		function handleInputChange(e) {
			let target = e.target;
			if (e.target.type !== 'range') {
				target = document.getElementById('range');
			} 
			const min = Number(target.min);
			const max = Number(target.max);
			const val = Number(target.value);
			const calculated = ( min === max ? 0 : (val - min) * 100 / (max - min) ) + '% 100%'
			target.style.backgroundSize = calculated;
			textToImageSettings.n = val;
			target.nextElementSibling.innerText = val;
		};

		rangeInputs.forEach(function(input) {
			input.addEventListener('input', handleInputChange);
		});
	};

	function addTitlelisteners() {
		let divs = document.querySelectorAll('.icon_info');
		divs.forEach(function(div) {
			div.addEventListener('click', function (event) {
				let elem = event.target.parentElement.parentElement;
				elem.children[0].classList.remove('hidden');
				let top = elem.offsetTop - elem.children[0].clientHeight - 5 + 'px;';
				elem.children[0].setAttribute('style', 'top:' + top);
			});

			div.addEventListener('mouseleave', function (event) {
				event.target.parentElement.parentElement.children[0].classList.add('hidden');
			});
		});
	};

	function createSelects() {
		$('#sel_models').select2({}).on('select2:select', function(e) {
			let model = e.currentTarget.value;
			textToImageSettings.model = model;
			changeParas(false);
		});

		$('#sel_size').select2({}).on('select2:select', function(e) {
			textToImageSettings.size = e.currentTarget.value;
		});


		$('#sel_response_format').select2({}).on('select2:select', function(e) {
			textToImageSettings.response_format = e.currentTarget.value;
		});


		$('#sel_style').select2({}).on('select2:select', function(e) {
			textToImageSettings.style = e.currentTarget.value;
		});
	};

	function changeParas(bRestore) {
		// change other parametrs for new model
		const model = textToImageSettings.model;
		let max = 1;
		if (bRestore) {
			if (textToImageSettings.hd)
				elements.checkBoxQuality.setAttribute('checked', '');
			$('#sel_models').val(textToImageSettings.model).trigger('change');
			$('#sel_response_format').val(textToImageSettings.response_format).trigger('change');
			$('#sel_style').val(textToImageSettings.style).trigger('change');
		}

		if (model === 'dall-e-2') {
			textToImageSettings.maxTokens = 1000;
			max = 10;
			elements.checkBoxQuality.setAttribute('disabled', '');
			document.getElementById('sel_style').setAttribute('disabled', '');
			$('#opt_256').prop('disabled', false);
			$('#opt_512').prop('disabled', false);
			$('#opt_1024').prop('disabled', true);
			$('#opt_1792').prop('disabled', true);
			if (textToImageSettings.size.includes('1792'))
				textToImageSettings.size = '256x256';
		} else {
			textToImageSettings.maxTokens = 4000;
			elements.checkBoxQuality.removeAttribute('disabled');
			document.getElementById('sel_style').removeAttribute('disabled');
			textToImageSettings.n = 1;
			$('#opt_256').prop('disabled', true);
			$('#opt_512').prop('disabled', true);
			$('#opt_1024').prop('disabled', false);
			$('#opt_1792').prop('disabled', false);
			if (!textToImageSettings.size.includes('1024'))
				textToImageSettings.size = '1024x1024';
		}
		elements.lbModalLen.innerText = textToImageSettings.maxTokens;
		$('#sel_size').val(textToImageSettings.size).trigger('change');
		setCount(textToImageSettings.n, max);
		checkLen();
	};

	function setCount(val, max) {
		elements.inpCountSl.setAttribute('max', max);
		elements.inpCountSl.value = val;
		let event = document.createEvent('Event');
		event.initEvent('input', true, true);
		elements.inpCountSl.dispatchEvent(event);
	};

	function getSettings(prompt) {
		let settings = {
			prompt: prompt,
			model: textToImageSettings.model,
			n: textToImageSettings.n,
			response_format: textToImageSettings.response_format,
			size: textToImageSettings.size
		};
		if (settings.model === 'dall-e-3') {
			if (textToImageSettings.hd)
				settings.quality = 'hd';

			settings.style = textToImageSettings.style;
		};
		return settings;
	};

	function createLoader() {
		$('#loader-container').removeClass( 'hidden' );
		loader && (loader.remove ? loader.remove() : $('#loader-container')[0].removeChild(loader));
		loader = showLoader($('#loader-container')[0], getTranslated('Loading...'));
	};

	function destroyLoader() {
		$('#loader-container').addClass( 'hidden' )
		loader && (loader.remove ? loader.remove() : $('#loader-container')[0].removeChild(loader));
		loader = undefined;
	};

	function setError(error, bConst, bQuotaErr) {
		if (bQuotaErr) {
			elements.mainErrorLb.innerHTML = '<label style="martgin-bottom:5px">' + getTranslated('You exceeded your current quota, please check your plan and billing details.') + '</label>' +
			'<p></p> <label>' + getTranslated('For more information on this error, read the docs:') + '</label>' +
			'<br> <a target="_blank" class="text-link" href="https://platform.openai.com/docs/guides/error-codes/api-errors.">https://platform.openai.com/docs/guides/error-codes/api-errors.</a>';
		} else {
			elements.mainErrorLb.innerHTML = '<label>' + getTranslated(error) + '</label>';
		}
		elements.mainError.classList.remove('hidden');
		if (errTimeout) {
			clearTimeout(errTimeout);
			errTimeout = null;
		}
		if (!bConst)
			errTimeout = setTimeout(clearMainError, 5000);
	};

	function clearMainError() {
		elements.mainError.classList.add('hidden');
		elements.mainErrorLb.innerHTML = '';
	};

	function getTranslated(key) {
		return window.Asc.plugin.tr(key);
	};

	function checkLen() {
		let cur = Number(elements.lbTokens.innerText);
		if (cur > textToImageSettings.maxTokens)
			elements.prompt.classList.add('error_border');
		else
			elements.prompt.classList.remove('error_border');
	};

	function sendPluginMessage(message) {
		window.Asc.plugin.sendToPlugin('onWindowMessage', message);
	};

	function fetchData(settings) {
		createLoader();
		let header = {
			'Authorization': 'Bearer ' + apiKey,
			'Content-Type': 'application/json'
		};
		fetch(url, {
				method: 'POST',
				headers: header,
				body: JSON.stringify(settings),
			})
			.then(function(response) {
				return response.json()
			})
			.then(function(data) {
				if (data.error)
					throw data.error

				pasteImage('data:image/png;base64,' + data.data[0][textToImageSettings.response_format]);
			})
			.catch(function(error) {
				let bQuotaErr = error.type === 'insufficient_quota';
				setError(error.message, false, bQuotaErr);
				console.error('Error:', error);
			})
			.finally(function(){
				destroyLoader();
			});
	};

	function pasteImage(src) {
		const info = window.Asc.plugin.info;
		const size = textToImageSettings.size.split('x');
		const width = Number(size[0]);
		const height = Number(size[1]);
		// use array for version history
		let data = {};
		data[Date.now()] = {
			prompt: elements.prompt.value.trim(),
			src: src,
			width: width,
			height: height,
			active: true
		};
		data[1714056012959] =  {
			prompt: "apple",
				src: "data:image/png;base64,",
				width: 256,
				height: 256,
				active: false
		};
		data[1714040071559] = {
			prompt: 'Moon as apple',
			src: "data:image/png;base64,",
			width: 512,
			height: 512,
			active: false
		}
		data = JSON.stringify(data);
		const param = {
			guid : info.guid,
			widthPix : width,
			heightPix : height,
			width : width / info.mmToPx,
			height : height / info.mmToPx,
			imgSrc : src,
			data : data,
			// objectId : info.objectId,
			resize : true,
			recalculate: true
		};
		window.Asc.plugin.executeMethod("AddOleObject", [param]);
	};

	window.Asc.plugin.onTranslate = function() {
		let elements = document.querySelectorAll('.i18n');

		for (let index = 0; index < elements.length; index++) {
			let element = elements[index];
			if (element.attributes['placeholder']) element.attributes['placeholder'].value = getTranslated(element.attributes['placeholder'].value);
			element.innerText = getTranslated(element.innerText);
		}
	};

	window.Asc.plugin.onThemeChanged = function(theme) {
		// todo в окна плагина не приходит сообщение о смене темы, пока единственный вариант - посылать это событие с темой из основного плагина (но на старте оно приходит)
		window.Asc.plugin.onThemeChangedBase(theme);

		let rule = '.select2-container--default.select2-container--open .select2-selection__arrow b { border-color : ' + window.Asc.plugin.theme['text-normal'] + ' !important; }';
		let sliderBG, thumbBG
		if (theme.type.indexOf('dark') !== -1) {
			sliderBG = theme.Border || '#757575';
			// for dark '#757575';
			// for contrast dark #616161
			thumbBG = '#fcfcfc';
		} else {
			sliderBG = '#efefef';
			thumbBG = '#c0c0c0';
		}
		rule += '\n .white_bg { background-color: ' + theme['background-normal'] + ' !important; }';
		rule += '\n .gray_bg { background-color: ' + theme['background-toolbar'] + ' !important; }';
		rule += '\n input[type="range"] { background-color: '+sliderBG+' !important; background-image: linear-gradient('+thumbBG+', '+thumbBG+') !important; }';
		rule += '\n input[type="range"]::-webkit-slider-thumb { background: '+thumbBG+' !important; }';
		rule += '\n input[type="range"]::-moz-range-thumb { background: '+thumbBG+' !important; }';
		rule += '\n input[type="range"]::-ms-thumb { background: '+thumbBG+' !important; }';
		
		let styleTheme = document.createElement('style');
		styleTheme.type = 'text/css';
		styleTheme.innerHTML = rule;
		document.getElementsByTagName('head')[0].appendChild(styleTheme);
	};

	window.Asc.plugin.attachEvent('onApiKey', function(settings) {
		apiKey = JSON.parse(settings).apiKey;
		console.log(apiKey);
	});

	window.Asc.plugin.attachEvent('onSaveSetting', function() {
		localStorage.setItem(localStorageKey, JSON.stringify(textToImageSettings));
	});

})(window, undefined);
